DROP TABLE IF EXISTS `chat_message`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `chat_message` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` varchar(20) NOT NULL,
  `conversation_id` bigint NOT NULL,
  `user_id` bigint NOT NULL,
  `role` varchar(16) NOT NULL COMMENT 'system/user/assistant/tool',
  `content` mediumtext,
  `content_format` varchar(16) NOT NULL DEFAULT 'text',
  `parent_id` bigint DEFAULT NULL,
  `status` varchar(16) NOT NULL DEFAULT 'DONE' COMMENT 'PENDING/STREAMING/DONE/FAILED',
  `model_id` bigint DEFAULT NULL,
  `invocation_id` bigint DEFAULT NULL,
  `token_in` int DEFAULT NULL,
  `token_out` int DEFAULT NULL,
  `cost_amount` decimal(18,6) DEFAULT NULL,
  `finish_reason` varchar(32) DEFAULT NULL,
  `error_msg` text,
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_conv_time` (`conversation_id`,`create_time`),
  KEY `idx_inv` (`invocation_id`)
) ENGINE=InnoDB AUTO_INCREMENT=103 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
