DROP TABLE IF EXISTS `llm_model`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `llm_model` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `provider_id` bigint NOT NULL,
  `endpoint_id` bigint NOT NULL,
  `model_name` varchar(128) NOT NULL COMMENT 'remote model name, e.g. gpt-4o-mini',
  `display_name` varchar(128) DEFAULT NULL,
  `capability_json` json DEFAULT NULL COMMENT '{"stream":true,"json":true,"tools":true,"vision":false,"thinking":false}',
  `context_window` int DEFAULT NULL,
  `status` char(1) NOT NULL DEFAULT '0',
  `tenant_id` varchar(20) DEFAULT '000000' COMMENT '部门Id',
  `create_dept` bigint DEFAULT NULL COMMENT '部门Id',
  `create_by` bigint DEFAULT NULL COMMENT '创建者',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_by` bigint DEFAULT NULL COMMENT '更新者',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  `del_flag` char(1) DEFAULT '0' COMMENT '删除标志(0-正常,1-删除)',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_provider_model` (`model_name`)
) ENGINE=InnoDB AUTO_INCREMENT=1004 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

