DROP TABLE IF EXISTS `wf_task`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `wf_task` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT '000000',
  `instance_id` bigint NOT NULL,
  `node_instance_id` bigint NOT NULL,
  `assignee_id` bigint NOT NULL COMMENT '处理人',
  `operator_id` bigint DEFAULT NULL,
  `status` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'TODO/DONE/CANCELED',
  `action` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT 'APPROVE/REJECT/TRANSFER/ADD_SIGN/WITHDRAW',
  `transfer_from` bigint DEFAULT NULL,
  `transfer_time` datetime DEFAULT NULL,
  `add_from` int DEFAULT NULL,
  `add_time` datetime DEFAULT NULL,
  `comment` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `type` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `finish_time` datetime DEFAULT NULL,
  `version` int NOT NULL,
  `create_dept` bigint DEFAULT NULL,
  `create_by` bigint DEFAULT NULL,
  `create_time` datetime DEFAULT NULL,
  `update_by` bigint DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  `del_flag` char(1) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_assignee_status` (`tenant_id`,`assignee_id`,`status`),
  KEY `idx_inst` (`tenant_id`,`instance_id`),
  KEY `idx_node_inst` (`node_instance_id`)
) ENGINE=InnoDB AUTO_INCREMENT=45 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='审批任务';
/*!40101 SET character_set_client = @saved_cs_client */;

