--
-- Table structure for table `wf_transition_log`
--

DROP TABLE IF EXISTS `wf_transition_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `wf_transition_log` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `tenant_id` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `def_id` bigint NOT NULL COMMENT '流程定义Id',
  `def_version` int NOT NULL COMMENT '流程定义版本',
  `instance_id` bigint NOT NULL COMMENT '流程实例ID',
  `node_instance_id` bigint DEFAULT NULL COMMENT '本次动作关联的节点实例ID（可选）',
  `task_id` bigint DEFAULT NULL COMMENT '本次动作关联的任务ID（可选）',
  `from_node_key` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '来源节点Key（START时可为空）',
  `to_node_key` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '目标节点Key（END时可为空）',
  `action` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'START/APPROVE/REJECT/GATEWAY/ROLLBACK/WITHDRAW/TRANSFER/END',
  `operator_type` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'SYSTEM/USER',
  `operator_id` bigint DEFAULT NULL COMMENT 'operator_type=USER时为用户ID',
  `comment` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '审批意见/退回原因/转办备注（前端展示用）',
  `condition_expr` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '网关命中条件表达式快照',
  `variables_snapshot` json DEFAULT NULL COMMENT '参与条件判断/展示的变量快照',
  `result` varchar(16) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'SUCCESS' COMMENT 'SUCCESS/FAIL',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_inst_time` (`tenant_id`,`instance_id`,`create_time`,`id`),
  KEY `idx_def` (`tenant_id`,`def_id`,`def_version`),
